import base64, json, urllib.request, os

api_key = "AIzaSyBtrX5vqKXEvEMSfeLjJoCTl3X2LFTl4T4"
files = [
    "/home/franklinbaldo/.openclaw/media/inbound/file_191---5cec8112-28a5-442d-8eee-0fae4edd0807.ogg",
    "/home/franklinbaldo/.openclaw/media/inbound/file_191---233c75f7-420d-45c2-ad1d-e141fda74314.ogg"
]

for i, audio_file in enumerate(files):
    if not os.path.exists(audio_file):
        print(f"Audio {i+1}: File not found.")
        continue
    with open(audio_file, "rb") as f:
        audio_b64 = base64.b64encode(f.read()).decode()
    payload = json.dumps({"contents": [{"parts": [
        {"inline_data": {"mime_type": "audio/ogg", "data": audio_b64}},
        {"text": "Transcreva este áudio em português. Responda apenas com a transcrição."}
    ]}]}).encode()
    req = urllib.request.Request(
        f"https://generativelanguage.googleapis.com/v1beta/models/gemini-2.0-flash:generateContent?key={api_key}",
        data=payload, headers={"Content-Type": "application/json"}
    )
    try:
        with urllib.request.urlopen(req, timeout=30) as resp:
            data = json.loads(resp.read())
            text = data["candidates"][0]["content"]["parts"][0]["text"]
            print(f"Transcrição {i+1}: {text}")
    except Exception as e:
        print(f"Erro na Transcrição {i+1}: {e}")
EOF
